async function seedSocialScience1Malayalam() {
    try {
        await mongoose.connect(MONGODB_URI);
        console.log('Connected to MongoDB');

        const parsedQuestions = [];
        for (let item of rawData) {
            const correctIndex = item.options.indexOf(item.answer);
            parsedQuestions.push({
                question: item.question,
                options: item.options,
                correctIndex: correctIndex !== -1 ? correctIndex : 0,
                level: 1,
                board: "Kerala State",
                class: "10th (SSLC)",
                subject: "Social Science I",
                chapter: item.chapter,
                medium: "Malayalam"
            });
        }

        for (const q of parsedQuestions) {
            const exists = await Question.findOne({
                question: q.question,
                subject: q.subject,
                medium: q.medium,
                board: q.board,
                class: q.class
            });

            if (!exists) {
                await Question.create(q);
                console.log(`Added: [${q.medium}] ${q.question.substring(0, 40)}...`);
            } else {
                console.log(`Skipped (Duplicate): [${q.medium}] ${q.question.substring(0, 40)}...`);
            }
        }

        console.log('Social Science I Malayalam seeding completed successfully!');
    } catch (error) {
        console.error('Error seeding data:', error);
    } finally {
        await mongoose.disconnect();
    }
}

seedSocialScience1Malayalam();
